"""Pipeline: chaining transformers and a final estimator."""
import numpy as np
from sklearn.base import BaseEstimator


class Pipeline(BaseEstimator):
    def __init__(self, steps, *, memory=None, verbose=False):
        self.steps = steps  # list of (name, estimator) tuples
        self.memory = memory
        self.verbose = verbose

    def get_params(self, deep=True):
        params = {'steps': self.steps}
        if deep:
            for name, est in self.steps:
                for key, val in est.get_params(deep=True).items():
                    params[f'{name}__{key}'] = val
        return params

    def set_params(self, **params):
        step_params = {}
        for key, val in params.items():
            if '__' in key:
                name, param = key.split('__', 1)
                step_params.setdefault(name, {})[param] = val
            elif key == 'steps':
                self.steps = val
        for name, sub_params in step_params.items():
            for step_name, est in self.steps:
                if step_name == name:
                    est.set_params(**sub_params)
                    break
        return self

    def _transform_steps(self, X, y=None, fit=False):
        Xt = X
        for name, transformer in self.steps[:-1]:
            if fit:
                if hasattr(transformer, 'fit_transform'):
                    Xt = transformer.fit_transform(Xt, y)
                else:
                    transformer.fit(Xt, y)
                    Xt = transformer.transform(Xt)
            else:
                Xt = transformer.transform(Xt)
        return Xt

    def fit(self, X, y=None):
        Xt = self._transform_steps(X, y, fit=True)
        final_name, final_est = self.steps[-1]
        final_est.fit(Xt, y)
        return self

    def predict(self, X):
        Xt = self._transform_steps(X)
        return self.steps[-1][1].predict(Xt)

    def fit_predict(self, X, y=None):
        return self.fit(X, y).predict(X)

    def transform(self, X):
        """Transform through all steps (useful when final step is a transformer)."""
        Xt = self._transform_steps(X)
        final = self.steps[-1][1]
        if hasattr(final, 'transform'):
            return final.transform(Xt)
        return Xt

    def fit_transform(self, X, y=None):
        Xt = self._transform_steps(X, y, fit=True)
        final = self.steps[-1][1]
        if hasattr(final, 'fit_transform'):
            return final.fit_transform(Xt, y)
        final.fit(Xt, y)
        if hasattr(final, 'transform'):
            return final.transform(Xt)
        return Xt

    def score(self, X, y):
        Xt = self._transform_steps(X)
        return self.steps[-1][1].score(Xt, y)


def make_pipeline(*estimators):
    """Convenience function to create a Pipeline with auto-generated names."""
    steps = []
    name_count = {}
    for est in estimators:
        name = type(est).__name__.lower()
        if name in name_count:
            name_count[name] += 1
            name = f'{name}-{name_count[name]}'
        else:
            name_count[name] = 1
        steps.append((name, est))
    return Pipeline(steps)
